  1→//! File discovery with glob/ignore support.
  2→//!
  3→//! Walks a directory tree to find source files for analysis, respecting
  4→//! `.gitignore`, `.shatterignore`, and user-specified include/exclude patterns.
  5→
  6→use std::path::{Path, PathBuf};
  7→
  8→use globset::{Glob, GlobSet, GlobSetBuilder};
