 10→/// Supported language, detected by file extension.
 11→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
 12→pub enum Language {
 13→    TypeScript,
 14→    Go,
 15→    Rust,
 16→}
 17→
 18→impl Language {
 19→    /// Detect language from a file extension string (without the leading dot).
 20→    pub fn from_extension(ext: &str) -> Option<Self> {
 21→        match ext {
 22→            "ts" | "tsx" => Some(Language::TypeScript),
 23→            "go" => Some(Language::Go),
 24→            "rs" => Some(Language::Rust),
 25→            _ => None,
 26→        }
 27→    }
 28→
 29→    /// Returns the language name as used in the crypto registry TOML.
 30→    pub fn as_registry_str(&self) -> &'static str {
 31→        match self {
 32→            Language::TypeScript => "typescript",
 33→            Language::Go => "go",
 34→            Language::Rust => "rust",
 35→        }
 36→    }
 37→}
 38→
 39→/// Options controlling which files are discovered.
 40→#[derive(Debug, Clone)]
 41→pub struct DiscoveryOptions {
 42→    /// Glob patterns for files to include (e.g. `["**/*.ts"]`). Empty means all supported files.
 43→    pub include_patterns: Vec<String>,
 44→    /// Glob patterns for files to exclude (e.g. `["**/vendor/**"]`).
 45→    pub exclude_patterns: Vec<String>,
 46→    /// Whether to respect `.gitignore` files.
 47→    pub respect_gitignore: bool,
 48→    /// Maximum directory traversal depth. `None` means unlimited.
 49→    pub max_depth: Option<usize>,
 50→}
 51→
 52→impl Default for DiscoveryOptions {
 53→    fn default() -> Self {
 54→        Self {
 55→            include_patterns: vec![],
 56→            exclude_patterns: vec![],
 57→            respect_gitignore: true,
 58→            max_depth: None,
 59→        }
 60→    }
 61→}
 62→
 63→/// Default directory/file patterns that are always excluded.
 64→const DEFAULT_EXCLUDES: &[&str] = &[
 65→    "**/node_modules/**",
 66→    "**/vendor/**",
 67→    "**/dist/**",
 68→    "**/target/**",
 69→    "**/__tests__/**",
 70→    "**/*.test.ts",
 71→    "**/*_test.go",
 72→];
 73→
 74→/// Errors that can occur during file discovery.
 75→#[derive(Debug, thiserror::Error)]
 76→pub enum DiscoveryError {
 77→    #[error("I/O error: {0}")]
 78→    Io(#[from] std::io::Error),
 79→    #[error("invalid glob pattern '{pattern}': {source}")]
 80→    InvalidPattern {
 81→        pattern: String,
 82→        source: globset::Error,
 83→    },
 84→}
 85→
 86→/// Discover source files under `root`, returning each file's path and detected language.
 87→///
 88→/// Applies default exclusions, user-specified include/exclude patterns,
 89→/// `.gitignore` rules (if `options.respect_gitignore` is true), and
 90→/// `.shatterignore` rules.
 91→pub fn discover_files(
 92→    root: &Path,
 93→    options: &DiscoveryOptions,
 94→) -> Result<Vec<(PathBuf, Language)>, DiscoveryError> {
 95→    let include_set = build_glob_set(&options.include_patterns)?;
 96→    let exclude_set = build_glob_set(&options.exclude_patterns)?;
 97→    let default_exclude_set = build_glob_set(
 98→        &DEFAULT_EXCLUDES.iter().map(|s| (*s).to_string()).collect::<Vec<_>>(),
 99→    )?;
